def first_non_repeating_stream(stream):
    result = []
    count = {}
    order = []
    for ch in stream:
        if ch not in count:
            count[ch] = 1
            order.append(ch)
        else:
            count[ch] += 1
        first = ""
        for c in order:
            if count[c] == 1:
                first = c
                break
        result.append(first)
    return result

