import unittest

class TestSolution(unittest.TestCase):
    def test_example_1(self):
        self.assertEqual(first_non_repeating_stream("aabcbd"), ['a', '', 'b', 'b', 'c', 'c'])

    def test_example_2(self):
        self.assertEqual(first_non_repeating_stream("abc"), ['a', 'a', 'a'])

    def test_example_3(self):
        self.assertEqual(first_non_repeating_stream("aabb"), ['a', '', 'b', ''])

    def test_hidden_empty(self):
        self.assertEqual(first_non_repeating_stream(""), [])

    def test_hidden_single_char(self):
        self.assertEqual(first_non_repeating_stream("z"), ['z'])

    def test_hidden_all_same(self):
        self.assertEqual(first_non_repeating_stream("aaaa"), ['a', '', '', ''])

    def test_hidden_alternating(self):
        self.assertEqual(first_non_repeating_stream("abab"), ['a', 'a', 'b', ''])

    def test_hidden_later_unique(self):
        self.assertEqual(first_non_repeating_stream("aabbc"), ['a', '', 'b', '', 'c'])

    def test_hidden_two_chars(self):
        self.assertEqual(first_non_repeating_stream("ab"), ['a', 'a'])

    def test_hidden_complex(self):
        self.assertEqual(first_non_repeating_stream("abacdc"), ['a', 'a', 'b', 'b', 'b', 'b'])

if __name__ == '__main__':
    unittest.main()
